local function check_permissions()
  local auth_header = ngx.req.get_headers()['Authorization']
  if not auth_header then
    ngx.status = 401
    ngx.say('Unauthorized: Missing authentication token.')
    ngx.exit(401)
  end

  -- Validate authentication token (replace with actual logic)
  if auth_header ~= 'Bearer TOKEN' then
    ngx.status = 403
    ngx.say('Forbidden: Invalid authentication token.')
    ngx.exit(403)
  end

  local user_role = ngx.req.get_headers()['X-User-Role']
  local uri = ngx.var.uri

  if string.find(uri, '/admin') or string.find(uri, '/api') then
    return true
  end

  -- Compare user roles using string matching
  if user_role == 'admin' then
    return true
  elseif user_role == 'editor' and string.find(uri, '/content') then
    return true
  else
    ngx.status = 403
    ngx.say('Forbidden: User does not have permission to access this resource.')
    ngx.exit(403)
  end
end

if not check_permissions() then
  ngx.status = 403
  ngx.say('Forbidden: Permission denied.')
  ngx.exit(403)
